(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[557],{2931:function(t,e,i){Promise.resolve().then(i.bind(i,1370))},1370:function(t,e,i){"use strict";i.r(e),i.d(e,{default:function(){return l}});var a=i(7437),n=i(7467),s=i(8678),o=i(4266),r=i(9888),c=i(4955);function l(){let t=(0,r.aS)("interior");return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)("section",{className:"pt-32 pb-16 bg-[var(--color-bg-primary)]",children:(0,a.jsx)("div",{className:"container",children:(0,a.jsx)(n.M$,{eyebrow:"Интерьеры",title:"Дизайн пространств",subtitle:"Интерьеры, где каждая деталь создаёт атмосферу и характер места",align:"center"})})}),(0,a.jsx)("section",{className:"pb-24 bg-[var(--color-bg-primary)]",children:(0,a.jsx)("div",{className:"container",children:(0,a.jsx)(s.v3,{className:"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8",children:t.map(t=>(0,a.jsx)(s.xH,{children:(0,a.jsx)(n.t,{project:t})},t.id))})})}),(0,a.jsx)(o.t7,{title:c.O1.cta.title,text:c.O1.cta.text})]})}},4266:function(t,e,i){"use strict";i.d(e,{sK:function(){return s.ProcessTimeline},t:function(){return n.ContactForm},t7:function(){return a.CTASection}}),i(9157),i(6372),i(234),i(7618),i(3703);var a=i(8950),n=i(5839),s=i(717)},4955:function(t,e,i){"use strict";i.d(e,{G:function(){return n},JA:function(){return a},KN:function(){return r},Nk:function(){return o},O1:function(){return s},Po:function(){return l},VE:function(){return c}});let a={name:"Nazarenko Architects",description:"Архитектура и дизайн пространств, созданных для жизни",architect:"Евгений Назаренко",email:"studio@nazarenko.design",phone:"+7 (495) 123-45-67",address:"Москва, Россия",social:{instagram:"https://instagram.com/nazarenko.architects",pinterest:"https://pinterest.com/nazarenkoarchitects",behance:"https://behance.net/nazarenkoarchitects"}},n=[{name:"Проекты",href:"/projects"},{name:"Архитектура",href:"/architecture"},{name:"Интерьеры",href:"/interiors"},{name:"О студии",href:"/about"},{name:"Процесс",href:"/process"},{name:"Публикации",href:"/publications"},{name:"Контакты",href:"/contact"}],s={featured:{eyebrow:"Избранные работы",title:"Проекты, определяющие современную архитектуру"},philosophy:{eyebrow:"Философия",title:"Архитектура как искусство жить",text:"Мы создаём пространства, которые работают на жизнь своих обитателей. Каждый проект начинается с глубокого понимания человека — его привычек, желаний, способа видеть мир. Результат — архитектура, которая не демонстрирует себя, а создаёт рамку для счастливой жизни."},services:{eyebrow:"Услуги",items:[{title:"Архитектура",description:"Проектирование частных домов и общественных зданий с нуля"},{title:"Дизайн интерьеров",description:"Создание интерьеров, где каждая деталь продумана"},{title:"Авторский надзор",description:"Контроль реализации проекта на всех этапах строительства"}]},cta:{title:"Готовы обсудить ваш проект?",text:"Расскажите о своих идеях — мы найдём лучшее решение"}},o={hero:{eyebrow:"О студии",title:"Евгений Назаренко",subtitle:"Архитектор и дизайнер интерьеров"},bio:"Евгений Назаренко — архитектор, создающий современные пространства, где архитектура, интерьер и атмосфера соединяются в единую композицию.\n\nВ своей работе архитектор опирается на принципы минимализма, внимание к деталям и глубокое понимание того, как люди взаимодействуют с пространством. Каждый проект — это диалог с заказчиком, результатом которого становится уникальное решение, отвечающее всем требованиям современной жизни.\n\nПриоритет — качество над количеством. В работе только с несколькими проектами одновременно, чтобы уделить каждому максимальное внимание.",principles:[{title:"Индивидуальность",description:"Каждый проект создаётся с нуля под конкретного человека и его образ жизни"},{title:"Целостность",description:"Архитектура, интерьер и ландшафт работают как единое целое"},{title:"Внимание к деталям",description:"Каждый элемент проекта продуман до мельчайших деталей"},{title:"Устойчивость",description:"Использование экологичных материалов и энергоэффективных решений"}]},r={hero:{eyebrow:"Процесс",title:"Как мы работаем"},steps:[{number:"01",title:"Знакомство и анализ",description:"На первой встрече мы слушаем. Изучаем образ жизни, привычки, пожелания. Анализируем участок, изучаем контекст. Формируем техническое задание.",duration:"1-2 недели"},{number:"02",title:"Концепция и идея",description:"На основе анализа разрабатываем архитектурную концепцию. Создаём мудборды, первые эскизы. Презентуем видение будущего пространства.",duration:"2-4 недели"},{number:"03",title:"Архитектурная разработка",description:"Детальная проработка всех разделов проекта: архитектура, конструктив, инженерия. Согласование решений с заказчиком.",duration:"2-4 месяца"},{number:"04",title:"Детализация и визуализация",description:"Создание 3D-визуализаций, подбор материалов, разработка мебели и освещения. Доведение каждой детали до совершенства.",duration:"1-3 месяца"},{number:"05",title:"Реализация и надзор",description:"Авторский надзор за строительством. Контроль качества материалов и работ. Решение всех возникающих вопросов.",duration:"весь период строительства"}]},c={hero:{eyebrow:"Контакты",title:"Начнём проект?",subtitle:"Расскажите о своих идеях — мы ответим в течение 24 часов"},form:{name:"Имя",phone:"Телефон",email:"Email",projectType:"Тип проекта",projectTypes:[{value:"",label:"Выберите тип проекта"},{value:"architecture",label:"Архитектура"},{value:"interior",label:"Дизайн интерьера"},{value:"both",label:"Архитектура и интерьер"}],message:"Расскажите о вашем проекте",submit:"Отправить заявку",sending:"Отправка...",success:"Заявка отправлена!",error:"Что-то пошло не так. Попробуйте ещё раз."}},l=[{id:"1",title:"Евгений Назаренко: \xabХороший дом — это тишина\xbb",source:"AD Russia",date:"Декабрь 2024",image:"https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?w=800&q=80"},{id:"2",title:"10 самых ожидаемых архитектурных проектов 2025",source:"Forbes Life",date:"Ноябрь 2024",image:"https://images.unsplash.com/photo-1600566753086-00f18fb6b3ea?w=800&q=80"},{id:"3",title:"Минимализм возвращается: новый взгляд на современную архитектуру",source:"Interior Digest",date:"Октябрь 2024",image:"https://images.unsplash.com/photo-1600210492493-0946911123ea?w=800&q=80"},{id:"4",title:"Дом как скульптура: проекты Nazarenko Architects",source:"Architectural Digest",date:"Сентябрь 2024",image:"https://images.unsplash.com/photo-1600585154340-be6161a56a0c?w=800&q=80"}]},9888:function(t,e,i){"use strict";i.d(e,{aS:function(){return n},q:function(){return a}});let a=[{id:"1",slug:"villa-luminosa",title:"Villa Luminosa",subtitle:"Частный дом на берегу озера",category:"architecture",year:2024,location:"Московская область, Россия",area:"650 м\xb2",description:"Современный частный дом с панорамным остеклением, где природа становится частью интерьера.",longDescription:"Проект Villa Luminosa — это результат глубокого погружения в философию жизни заказчика. Расположенный на берегу живописного озера, дом спроектирован таким образом, чтобы максимально раствориться в окружающем ландшафте, при этом предлагая максимальный уровень комфорта и приватности.\n\nОсновная концепция — \xabдом как рамка для природы\xbb. Огромные панорамные окна от пола до потолка превращают каждый день в путешествие по сменяющимся сезонам. Зимой — это вид на заснеженные сосны и розовеющий горизонт. Летом — бесконечная игра света на водной глади.\n\nАрхитектура дома построена на контрасте: массивный цокольный этаж из натурального камня создаёт ощущение надёжности и укоренённости, в то время как верхние уровни, облицованные светлым деревом, стремятся вверх, к свету.\n\nВнутреннее пространство организовано вокруг центрального двусветного холла с камином — сердца дома, где собирается вся семья. Из холла открываются виды на все ключевые пространства: кухню-столовую, террасу с видом на озеро, приватную зону спален на верхнем уровне.\n\nОсобое внимание уделено материалам: натуральный дуб, итальянский травертин, бронзовые детали фурнитуры. Каждый элемент выбран не только за эстетические качества, но и за тактильные ощущения, которые он создаёт.",images:["https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?w=1600&q=80","https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?w=1600&q=80","https://images.unsplash.com/photo-1600566753190-17f0baa2a6c3?w=1600&q=80","https://images.unsplash.com/photo-1600585154340-be6161a56a0c?w=1600&q=80","https://images.unsplash.com/photo-1600573472550-8090b5e0745e?w=1600&q=80"],materials:["Натуральный камень","Дуб","Итальянский травертин","Бронза","Стекло","Штукатурка"],featured:!0},{id:"2",slug:"penthouse-aurora",title:"Penthouse Aurora",subtitle:"Двухуровневый пентхаус в центре Москвы",category:"interior",year:2024,location:"Москва, Россия",area:"420 м\xb2",description:"Интерьер пентхауса, где роскошь современности сочетается с вневременной элегантностью.",longDescription:"Penthouse Aurora — проект, в котором мы переосмыслили понятие городской роскоши. Расположенный на верхних этажах одного из самых престижных жилых комплексов Москвы, этот двухуровневый пентхаус потребовал особого подхода к планировке и световому дизайну.\n\nОсновная задача состояла в создании пространства, которое ощущается одновременно просторным и уютным, парадным и приватным. Этот баланс достигнут через чёткое зонирование: общественная зона первого этажа — открытая, наполненная светом, с двухуровневым атриумом. Приватная зона второго этажа — более интимная, с мягкими материалами и приглушённым освещением.\n\nЦветовая палитра построена на игре тёплых нейтралов: от почти белого натурального шёлка до глубокого оттенка тёплого дерева. Акцентные элементы — бронзовые детали, натуральный оникс, единичные произведения искусства — создают точки фокуса, не перегружая пространство.\n\nОсобое внимание в проекте уделено техническим системам: умный дом полностью интегрирован, климат-контроль работает бесшумно и незаметно, а система освещения позволяет создавать любые сценарии — от яркого дневного света до интимной вечерней атмосферы.",images:["https://images.unsplash.com/photo-1600607687644-aac4c3eac7f4?w=1600&q=80","https://images.unsplash.com/photo-1600566753086-00f18fb6b3ea?w=1600&q=80","https://images.unsplash.com/photo-1600210492493-0946911123ea?w=1600&q=80","https://images.unsplash.com/photo-1600585154526-990dced4db0d?w=1600&q=80"],materials:["Натуральный шёлк","Дуб","Бронза","Оникс","Итальянский мрамор","Витражи"],featured:!0},{id:"3",slug:"house-of-silence",title:"House of Silence",subtitle:"Загородная резиденция в лесу",category:"architecture",year:2023,location:"Ленинградская область, Россия",area:"800 м\xb2",description:"Дом-убежище в сосновом лесу, спроектированный как место для тишины и перезагрузки.",longDescription:"House of Silence — это архитектурный манифест о важности тишины в современном мире. Расположенный в сосновом лесу в часе езды от Санкт-Петербурга, этот дом спроектирован как полная противоположность городскому шуму и информационной перегрузке.\n\nВнешне дом представляет собой строгий объём из дерева и бетона, почти неотличимый от окружающего ландшафта. Крыша покрыта мхом — дом буквально сливается с лесом. Но настоящая магия начинается внутри.\n\nИнтерьер построен на принципе \xab沉默\xbb — китайском понятии тишины как источника силы. Здесь нет лишних деталей, нет ярких цветов, нет отвлекающих элементов. Только пространство, свет, натуральные материалы и звук леса, проникающий сквозь большие окна.\n\nПланировка организована вокруг внутреннего двора с водоёмом — источника жизни и спокойствия. Все помещения обращены к этому двору или к лесу. Спальни расположены в отдельном крыле, максимально удалённом от общей зоны — для полной приватности и возможности уединения.\n\nВ доме нет телевизоров в привычном понимании. Вместо этого — библиотека с камином, медитационная комната, домашний кинотеатр с проектором на открытом воздухе. Это пространство для осознанной жизни.",images:["https://images.unsplash.com/photo-1613490493576-7fde63acd811?w=1600&q=80","https://images.unsplash.com/photo-1600047509807-ba8f99d2cdde?w=1600&q=80","https://images.unsplash.com/photo-1600566752355-35792bedcfea?w=1600&q=80","https://images.unsplash.com/photo-1600585154363-67eb9e2e2099?w=1600&q=80"],materials:["Сосна","Бетон","Мох","Натуральный камень","Сталь","Лён"],featured:!0},{id:"4",slug:"urban-loft-east",title:"Urban Loft East",subtitle:"Лофт в промышленном здании",category:"interior",year:2023,location:"Москва, Россия",area:"280 м\xb2",description:"Преобразование производственного пространства в современное жилое лофт-апартаменты.",longDescription:"Urban Loft East — проект трансформации бывшего промышленного здания в уникальное жилое пространство. Заказчик — коллекционер современного искусства — хотел создать дом-галерею, где произведения искусства станут полноценной частью архитектуры.\n\nИсходное пространство — бывший цех завода 1950-х годов постройки. Сохранившиеся кирпичные стены, высокие потолки, промышленные окна — всё это стало базой для создания аутентичного лофта с современным характером.\n\nОсновной приём — контраст исторических и современных элементов. Кирпичная кладка соседствует с полированным бетонным полом, старые металлические балки — с новыми стеклянными перегородками. Вместо замены старого — бережная интеграция нового.\n\nПространство организовано по принципу open plan: объединённая кухня-гостиная занимает центральную часть, приватные зоны (спальни, кабинет) вынесены в тихие углы. В центре — массивный остров-скульптура из чёрного камня, вокруг которого организована вся жизнь.\n\nОсобое место в проекте занимает коллекция искусства заказчика. Для каждого произведения разработаны специальные системы освещения и размещения. Некоторые работы интегрированы в архитектуру — например, инсталляция на потолке двусветного пространства.",images:["https://images.unsplash.com/photo-1600607687920-4e2a09cf159d?w=1600&q=80","https://images.unsplash.com/photo-1600566753376-12c8ab7fb75b?w=1600&q=80","https://images.unsplash.com/photo-1600585154084-4e5fe7c39198?w=1600&q=80","https://images.unsplash.com/photo-1600573472592-401b489a3cdc?w=1600&q=80"],materials:["Кирпич","Полированный бетон","Чёрный камень","Металл","Стекло","Кожа"],featured:!1},{id:"5",slug:"villa-bianchi",title:"Villa Bianchi",subtitle:"Классическая вилла с современным интерьером",category:"architecture",year:2023,location:"Рублёвка, Россия",area:"950 м\xb2",description:"Реконструкция исторической усадьбы с современной интерпретацией классической архитектуры.",longDescription:"Villa Bianchi — проект реконструкции и расширения исторической усадьбы на Рублёвском шоссе. Задача была непростой: сохранить дух классической русской усадьбы, при этом создав современное, функциональное пространство для жизни семьи с тремя детьми.\n\nАрхитектурное решение основано на уважении к существующему зданию. Главный дом отреставрирован с сохранением всех исторических деталей: лепнина, каминные порталы, парадная лестница. Но интерьер полностью переосмыслен.\n\nНовая программа потребовала расширения — мы пристроили современный объём с бассейном и SPA, полностью остеклённый и обращённый в сад. Этот пристройка контрастирует с основным объёмом, но гармонично дополняет его.\n\nИнтерьеры главного дома выдержаны в сдержанной палитре с акцентом на натуральные материалы: дубовый паркет, штукатурка, камень. Классическая мебель смешана с современными предметами дизайна — так создаётся ощущение дома с историей, но живого и актуального.\n\nЛандшафтный дизайн продолжает архитектурную идею: регулярный сад с липовыми аллеями, плодовый сад, огород — всё в лучших традициях русской усадьбы, но ухоженное и современное.",images:["https://images.unsplash.com/photo-1600585154340-be6161a56a0c?w=1600&q=80","https://images.unsplash.com/photo-1600047509358-9dc75507daeb?w=1600&q=80","https://images.unsplash.com/photo-1600566752734-2a0cd66c42ff?w=1600&q=80","https://images.unsplash.com/photo-1600210491892-03d54c0aaf87?w=1600&q=80"],materials:["Дуб","Итальянский мрамор","Лепнина","Штукатурка","Камень","Латунь"],featured:!1},{id:"6",slug:"apartment-nordic",title:"Nordic Light",subtitle:"Скандинавский минимализм в Москве",category:"interior",year:2024,location:"Москва, Россия",area:"180 м\xb2",description:"Квартира в стиле скандинавского минимализма с акцентом на натуральность и функциональность.",longDescription:"Nordic Light — проект для молодой семьи, которая ценит простоту, функциональность и связь с природой. Квартира на north-east стороне с видом на Москву-реку стала идеальным холстом для создания светлого, наполненного воздухом пространства.\n\nФилософия скандинавского дизайна переосмыслена через призму современной московской жизни. Это не копия скандинавского интерьера, а адаптация его принципов: натуральные материалы, много света, функциональность, уют.\n\nПалитра — почти монохромная, с тёплыми нейтралами: белый, серый, оттенки натурального дерева. Акцентные цвета минимальны — пара подушек в глубоком синем, живое растение в углу.\n\nМебель — сочетание винтажных находок и современного дизайна. Каждый предмет выбран за функциональность и характер. Ничего случайного, но ничего холодного.\n\nОсобое внимание уделено освещению: помимо функциональных источников света, создана система декоративного освещения, которая позволяет менять настроение пространства в зависимости от времени дня и активности.",images:["https://images.unsplash.com/photo-1600210491369-e753d80a41f3?w=1600&q=80","https://images.unsplash.com/photo-1600566753190-17f0baa2a6c3?w=1600&q=80","https://images.unsplash.com/photo-1600585154526-990dced4db0d?w=1600&q=80"],materials:["Сосна","Лён","Шерсть","Бетон","Сталь","Стекло"],featured:!1}];function n(t){return a.filter(e=>e.category===t||"all"===e.category)}}},function(t){t.O(0,[894,773,467,380,971,117,744],function(){return t(t.s=2931)}),_N_E=t.O()}]);